function ProductCard({ nom, prix, categorie, stock, promotion, hideOutOfStock }) {
  // Retour anticipé : ne pas afficher le produit si rupture ET filtre actif
  if (hideOutOfStock && stock === 0) {
    return null;
  }

  const prixPromo = promotion ? prix * 0.9 : null;
  const stockStatus = stock === 0 ? 'rupture' : (stock <= 5 ? 'dernieres' : 'disponible');
  const categoryClass = {
    artisanat: 'bg-amber-100',
    alimentaire: 'bg-green-100',
    textile: 'bg-blue-100'
  }[categorie] || 'bg-gray-100';

  return (
    &lt;div className={`product-card ${categoryClass} p-4 rounded-lg shadow`}&gt;
      &lt;h3 className="font-bold"&gt;{nom}&lt;/h3&gt;

      {promotion && (
        &lt;div className="promotion-badge bg-red-500 text-white px-2 py-1 rounded text-sm inline-block"&gt;
          🔥 Promotion
        &lt;/div&gt;
      )}

      &lt;div className="price mt-2"&gt;
        {promotion ? (
          &lt;&gt;
            &lt;span className="old-price line-through text-gray-500"&gt;{prix.toLocaleString()} FCFA&lt;/span&gt;
            &lt;span className="new-price text-red-600 font-bold ml-2"&gt;{prixPromo.toLocaleString()} FCFA&lt;/span&gt;
          &lt;/&gt;
        ) : (
          &lt;span&gt;{prix.toLocaleString()} FCFA&lt;/span&gt;
        )}
      &lt;/div&gt;

      &lt;div className="stock mt-2"&gt;
        {stock === 0 ? (
          &lt;span className="text-red-600 font-semibold"&gt;⛔ Rupture de stock&lt;/span&gt;
        ) : stock <= 5 ? (
          &lt;span className="text-orange-600"&gt;⚠️ Dernières pièces ({stock} restant{stock > 1 ? 's' : ''})&lt;/span&gt;
        ) : (
          &lt;span className="text-green-600"&gt;✓ En stock ({stock} unités)&lt;/span&gt;
        )}
      &lt;/div&gt;

      &lt;button 
        className={`mt-3 px-4 py-1 rounded ${stock === 0 ? 'bg-gray-400 cursor-not-allowed' : 'bg-indigo-600 text-white'}`}
        disabled={stock === 0}
      &gt;
        {stock === 0 ? 'Indisponible' : 'Ajouter au panier'}
      &lt;/button&gt;
    &lt;/div&gt;
  );
}
```
